with open\('app/Http/Requests/API/ImagenAPIRequest.php', 'r'\) as f:
    content = f.read\(\)

old = """    public function manage\(\){
        $this->F = new FuncionesController\(\);

        try {

            $img = $this->manageImage\(\);
            $this->attaches\($img\);
            event\(new APIDenunciaEvent\($this->denuncia_id, $this->user_id\)\);

        }catch \(QueryException $e\){
            $Msg = new MessageAlertClass\(\);
            return $Msg->Message\($e\);
        }
        return $img;

    }"""

new = """    public function manage\(\){
        $this->F = new FuncionesController\(\);

        try {

            // manageImage\(\) ahora retorna un array con status/msg/urls
            $result = $this->manageImage\(\);

            // Solo disparar el evento si la imagen se guardó correctamente
            if \(isset\($result['status']\) && $result['status'] === 1\) {
                event\(new APIDenunciaEvent\($this->denuncia_id, $this->user_id\)\);
            }

        }catch \(QueryException $e\){
            $Msg = new MessageAlertClass\(\);
            return $Msg->Message\($e\);
        }
        return $result;

    }"""

if old in content:
    content = content.replace\(old, new, 1\)
    with open\('app/Http/Requests/API/ImagenAPIRequest.php', 'w'\) as f:
        f.write\(content\)
    print\("OK: manage\(\) actualizado"\)
else:
    print\("ERROR: texto no encontrado"\)
PYEOF)

